      photos: [ { mode:"link", url:"https://hinsyu-zukan.satumano-medakayasan.com/ryurin", caption:"参考：龍鱗（みんなのメダカ品種図鑑）", credit:"みんなのメダカ品種図鑑", usage:"参照リンクのみ（画像は転載しない）" } ],
