      photos: [ { mode:"link", url:"https://medakazukan.net/0870_boukyakunotubasa/", caption:"参考：忘却の翼 No.0870（改良メダカWEB図鑑）", credit:"改良メダカWEB図鑑", usage:"参照リンクのみ（画像は転載しない）" } ],
